68	#[tokio::main]
69	async fn main() -> anyhow::Result<()> {
70	    use std::sync::{atomic::AtomicBool, mpsc, Arc};
71	    use tokio_util::sync::CancellationToken;
72	
73	    let args = Cli::parse();
74	    init_logging(args.verbose);
75	
76	    // --list-devices: enumerate CPAL input devices and exit.
77	    if args.list_devices {
78	        use cpal::traits::{DeviceTrait, HostTrait};
79	        let host = cpal::default_host();
80	        println!("Available audio input devices (use name in audio.device in config.yaml):");
81	        println!();
82	        match host.input_devices() {
83	            Ok(devices) => {
84	                let mut found = false;
85	                for (idx, device) in devices.enumerate() {
86	                    found = true;
87	                    let cfg = device.default_input_config()
88	                        .map(|c| format!("{} ch @ {} Hz", c.channels(), c.sample_rate().0))
89	                        .unwrap_or_else(|_| "no supported config".to_string());
90	                    println!("  Device {}: {}", idx, cfg);
91	                }
92	                if !found {
93	                    println!("  (no input devices found)");
94	                }
95	            }
96	            Err(e) => eprintln!("Failed to enumerate devices: {e}"),
97	        }
98	        return Ok(());
99	    }
100	
101	    if let Some(cmd) = args.command {
102	        use hd_linux_voice::control::protocol::ControlRequest;
103	        use hd_linux_voice::control::client::send_command;
104	
105	        match cmd {
106	            Commands::Ping => {
107	                match send_command(ControlRequest::Ping) {
108	                    Ok(resp) => println!("{resp:?}"),
109	                    Err(e) => eprintln!("Error: {e}"),
110	                }
111	            }
112	            Commands::Switch { name } => {
113	                match send_command(ControlRequest::SwitchProfile { name }) {
114	                    Ok(resp) => println!("{resp:?}"),
115	                    Err(e) => eprintln!("Error: {e}"),
116	                }
117	            }
118	            Commands::Test { name } => {
119	                match send_command(ControlRequest::TestMacro { name }) {
120	                    Ok(resp) => println!("{resp:?}"),
121	                    Err(e) => eprintln!("Error: {e}"),
122	                }
123	            }
124	            Commands::Import { file } => {
125	                use hd_linux_voice::pack::Pack;
126	                match Pack::import(&file) {
127	                    Ok(pack) => println!("Successfully imported pack: {}", pack.name),
128	                    Err(e) => eprintln!("Import error: {e:#}"),
129	                }
130	            }
131	            Commands::Export { name, output } => {
132	                use hd_linux_voice::pack::{Pack, get_profiles_dir};
133	                let dir = get_profiles_dir().unwrap().join(&name);
134	                match Pack::load_from_dir(&dir) {
135	                    Ok(pack) => {
136	                        let out = output.unwrap_or_else(|| std::path::PathBuf::from(format!("{name}.hdpack")));
137	                        match pack.export(&dir, &out) {
138	                            Ok(_) => println!("Successfully exported pack to: {}", out.display()),
139	                            Err(e) => eprintln!("Export error: {e:#}"),
140	                        }
141	                    }
142	                    Err(e) => eprintln!("Error loading profile '{name}': {e:#}"),
143	                }
144	            }
145	            Commands::Edit => {
146	                hd_linux_voice::tui::run_editor().unwrap();
147	            }
148	        }
149	        return Ok(());
150	    }
151	
152	    tracing::info!("hd-linux-voice starting");
153	
154	    // === 1. Load config (fail-hard on any error) ===
155	    let mut config = hd_linux_voice::config::load(args.config.as_deref()).map_err(|e| {
156	        eprintln!("{e:#}");
157	        e
158	    })?;
159	
160	    // === 1a. Integrate ProfileManager (if no explicit config passed) ===
161	    if args.config.is_none() {
162	        use hd_linux_voice::pack::manager::ProfileManager;
163	        let manager = ProfileManager::load()?;
164	        if let Some(pack) = manager.get_active_pack()? {
165	            tracing::info!(profile = %pack.name, macros = pack.flatten().len(), "Applying active profile macros");
166	            config.macros = pack.flatten();
167	        }
168	    }
169	
170	    tracing::info!(
171	        ptt_key = %config.ptt.key,
172	        dwell_ms = config.timing.dwell_ms,
173	        gap_ms = config.timing.gap_ms,
174	        macros = config.macros.len(),
175	        "Config loaded"
176	    );
177	
178	    // === 1b. Preflight: validate all local model paths BEFORE threads (Phase 2) ===
179	    config.validate_model_paths().map_err(|e| {
180	        eprintln!("{e:#}");
181	        e
182	    })?;
183	
184	    // === 2. Parse PTT key code ===
185	    let ptt_key = hd_linux_voice::input::ptt::parse_key_code(&config.ptt.key)
186	        .map_err(|e| { eprintln!("{e:#}"); e })?;
187	
188	    // === 3. Preflight: verify /dev/input readable (fail-hard, D-11) ===
189	    hd_linux_voice::input::ptt::check_input_readable().map_err(|e| {
190	        eprintln!("{e:#}");
191	        e
192	    })?;
193	
194	    // === 4. Open uinput virtual keyboard (fail-hard, D-15) ===
195	    // Must happen BEFORE spawning any threads — if it fails, we exit cleanly.
196	    let virtual_kbd = hd_linux_voice::input::inject::open_uinput_device().map_err(|e| {
197	        eprintln!("{e:#}");
198	        e
199	    })?;
200	    tracing::info!("uinput virtual keyboard opened");
201	
202	    // === 5. Find PTT device ===
203	    let ptt_device = hd_linux_voice::input::ptt::find_ptt_device(ptt_key).map_err(|e| {
204	        eprintln!("{e:#}");
205	        e
206	    })?;
207	
208	    // === 6. Shared state ===
209	    let ptt_active = Arc::new(AtomicBool::new(false));
210	    let shutdown = CancellationToken::new();
211	
212	    // === 7. Spawn injection thread (std::thread, D-07) ===
213	    let (macro_tx, macro_rx) = mpsc::channel::<hd_linux_voice::input::inject::MacroCmd>();
214	    let inject_handle = hd_linux_voice::input::inject::spawn_injection_thread(virtual_kbd, macro_rx);
215	
216	    // === 8. Start CPAL audio stream (warm, D-04) ===
217	    let audio_handle = hd_linux_voice::audio::start_audio_stream(
218	        config.audio.device.as_deref(),
219	        Arc::clone(&ptt_active),
220	    )
221	        .map_err(|e| {
222	            let _ = macro_tx.send(hd_linux_voice::input::inject::MacroCmd::Shutdown);
223	            eprintln!("Audio error: {e:#}");
224	            e
225	        })?;
226	
227	    // === 9. Spawn PTT thread (std::thread, D-09, D-10) ===
228	    let ptt_handle = hd_linux_voice::input::ptt::spawn_ptt_thread(
229	        ptt_device,
230	        ptt_key,
231	        Arc::clone(&ptt_active),
232	        shutdown.clone(),
233	    );
234	
235	    // === 10. Spawn Phase 2 pipeline (OS threads; stdout JSONL only) ===
236	    //
237	    // Split the audio handle: the CPAL stream guard MUST remain on this
238	    // (main) thread.  Moving `cpal::Stream` into a worker thread that is
239	    // spawned from inside a nested helper and then dropped has been shown
240	    // to silently stop the ALSA/PipeWire callback on Linux.  Pass only the
241	    // ringbuf consumer into the pipeline.
242	    let hd_linux_voice::audio::AudioHandle {
243	        stream: _audio_stream_guard,
244	        consumer: audio_consumer,
245	        actual_config: _actual_cfg,
246	    } = audio_handle;
247	
248	    let pipeline_handles = hd_linux_voice::pipeline::coordinator::spawn_pipeline(
249	        audio_consumer,
250	        config.clone(),
251	        Arc::clone(&ptt_active),
252	        macro_tx.clone(),
253	        shutdown.clone(),
254	    )
255	    .map_err(|e| {
256	        // If pipeline preflight fails, stop injection thread before exiting.
257	        let _ = macro_tx.send(hd_linux_voice::input::inject::MacroCmd::Shutdown);
258	        eprintln!("{e:#}");
259	        e
260	    })?;
261	
262	    // === 10b. Spawn UDS control listener (Phase 4) ===
263	    hd_linux_voice::control::spawn_control_listener(pipeline_handles.dispatcher.clone()).await.map_err(|e| {
264	        tracing::error!("Failed to start control listener: {e:#}");
265	        e
266	    })?;
267	
268	    tracing::info!("Daemon running. Hold PTT and speak to emit JSONL transcripts. Ctrl+C or SIGTERM to exit.");
269	
270	    // === 11. Wait for SIGTERM or SIGINT ===
271	    let mut sigterm = tokio::signal::unix::signal(
272	        tokio::signal::unix::SignalKind::terminate()
273	    )?;
274	    let mut sigint = tokio::signal::unix::signal(
275	        tokio::signal::unix::SignalKind::interrupt()
276	    )?;
277	
278	    tokio::select! {
279	        _ = sigterm.recv() => tracing::info!("SIGTERM received"),
280	        _ = sigint.recv()  => tracing::info!("SIGINT received (Ctrl+C)"),
281	    }
282	
283	    // === 12. Graceful shutdown ===
284	    tracing::info!("Shutting down...");
285	
286	    // Cancel PTT thread (checks is_cancelled() between event batches)
287	    shutdown.cancel();
288	
289	    // Best-effort request STT shutdown + join pipeline threads (T-02-09).
290	    let mut pipeline_handles = pipeline_handles;
291	
292	    if let Some(mut stt) = pipeline_handles.stt.take() {
293	        stt.request_shutdown();
294	        stt.join_best_effort(std::time::Duration::from_millis(500));
295	    }
296	
297	    let pipeline_join = std::thread::spawn(move || pipeline_handles.pipeline.join());
298	    let output_join = std::thread::spawn(move || pipeline_handles.output.join());
299	    std::thread::sleep(std::time::Duration::from_millis(500));
300	    drop(pipeline_join);
301	    drop(output_join);
302	
303	    // Signal injection thread and wait for it to drain
304	    let _ = macro_tx.send(hd_linux_voice::input::inject::MacroCmd::Shutdown);
305	    if let Err(e) = inject_handle.join() {
306	        tracing::warn!("Injection thread panicked: {e:?}");
307	    }
308	
309	    // PTT thread: best-effort join — fetch_events() may block until next event
310	    let ptt_join = std::thread::spawn(move || ptt_handle.join());
311	    std::thread::sleep(std::time::Duration::from_millis(500));
312	    drop(ptt_join);
313	
314	    // Dropping _audio_stream_guard here stops the CPAL stream (RAII).
315	    drop(_audio_stream_guard);
316	
317	    tracing::info!("hd-linux-voice stopped");
318	    Ok(())
319	}
