4	use std::path::PathBuf;
5	use anyhow::{Context, Result};
6	use tokio::net::UnixListener;
7	use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader};
8	use crate::control::protocol::{ControlRequest, ControlResponse};
9	use crate::pipeline::dispatcher::Dispatcher;
10	use std::sync::Arc;
11	
12	/// Spawn the control channel listener on a Tokio task.
13	///
14	/// Listens on a Unix Domain Socket for commands from the CLI.
15	pub async fn spawn_control_listener(dispatcher: Arc<Dispatcher>) -> Result<()> {
16	    let socket_path = get_socket_path()?;
17	    
18	    // Clean up existing socket file if it exists
19	    if socket_path.exists() {
20	        std::fs::remove_file(&socket_path)
21	            .with_context(|| format!("Failed to remove existing socket: {}", socket_path.display()))?;
22	    }
23	
24	    let listener = UnixListener::bind(&socket_path)
25	        .with_context(|| format!("Failed to bind to UDS socket: {}", socket_path.display()))?;
26	    
27	    // Set permissions to 0600 (user only)
28	    #[cfg(unix)]
29	    {
30	        use std::os::unix::fs::PermissionsExt;
31	        std::fs::set_permissions(&socket_path, std::fs::Permissions::from_mode(0o600))?;
32	    }
33	
34	    tracing::info!("Control channel listening on: {}", socket_path.display());
35	
36	    tokio::spawn(async move {
37	        loop {
38	            match listener.accept().await {
39	                Ok((mut stream, _)) => {
40	                    let dispatcher_clone = Arc::clone(&dispatcher);
41	                    tokio::spawn(async move {
42	                        let (reader, mut writer) = stream.split();
43	                        let mut reader = BufReader::new(reader);
44	                        let mut line = String::new();
45	
46	                        if let Ok(n) = reader.read_line(&mut line).await {
47	                            if n == 0 { return; }
48	
49	                            let response = match serde_json::from_str::<ControlRequest>(&line) {
50	                                Ok(req) => {
51	                                    tracing::debug!("Control request: {:?}", req);
52	                                    match req {
53	                                        ControlRequest::Ping => ControlResponse::Pong,
54	                                        ControlRequest::SwitchProfile { name } => {
55	                                            match tokio::task::block_in_place(|| {
56	                                                handle_switch_profile(&name, &dispatcher_clone)
57	                                            }) {
58	                                                Ok(_) => ControlResponse::Ok,
59	                                                Err(e) => ControlResponse::Error { message: e.to_string() },
60	                                            }
61	                                        }
62	                                        ControlRequest::Shutdown => {
63	                                            // TODO: Trigger global shutdown
64	                                            ControlResponse::Ok
65	                                        }
66	                                        _ => ControlResponse::Error { message: "Not yet implemented".into() },
67	                                    }
68	                                }
69	                                Err(e) => ControlResponse::Error { message: format!("Invalid JSON: {e}") },
70	                            };
71	
72	                            if let Ok(resp_json) = serde_json::to_string(&response) {
73	                                let _ = writer.write_all(resp_json.as_bytes()).await;
74	                                let _ = writer.write_all(b"\n").await;
75	                            }
76	                        }
77	                    });
78	                }
79	                Err(e) => {
80	                    tracing::error!("Control listener accept error: {e}");
81	                }
82	            }
83	        }
84	    });
85	
86	    Ok(())
87	}
88	
89	fn handle_switch_profile(name: &str, dispatcher: &Dispatcher) -> Result<()> {
90	    use crate::pack::Pack;
91	    use crate::pack::manager::ProfileManager;
92	
93	    let dir = crate::pack::get_profiles_dir()?.join(name);
94	    let pack = Pack::load_from_dir(&dir)?;
95	    dispatcher.update_macros(pack.flatten());
96	
97	    // Update persistence so it survives restart
98	    let mut manager = ProfileManager::load().unwrap_or(ProfileManager { active_profile: None });
99	    manager.active_profile = Some(name.to_string());
100	    manager.save()?;
101	
102	    Ok(())
103	}
104	
105	fn get_socket_path() -> Result<PathBuf> {
106	    let xdg = xdg::BaseDirectories::with_prefix("hd-linux-voice");
107	
108	    xdg.place_runtime_file("hd-linux-voice.sock")
109	        .context("Failed to place UDS socket in runtime directory")
110	}
