5	/// Top-level daemon configuration.
6	/// Loaded from $XDG_CONFIG_HOME/hd-linux-voice/config.yaml (D-13, D-14).
7	#[derive(Debug, Clone, Deserialize, Serialize)]
8	#[serde(deny_unknown_fields)]
9	pub struct Config {
10	    pub ptt: PttConfig,
11	    pub timing: TimingConfig,
12	    #[serde(default)]
13	    pub audio: AudioConfig,
14	    #[serde(default)]
15	    pub pipeline: PipelineConfig,
16	    #[serde(default)]
17	    pub vad: VadConfig,
18	    #[serde(default)]
19	    pub stt: SttConfig,
20	    #[serde(default)]
21	    pub wake: WakeConfig,
22	    #[serde(default)]
23	    pub macros: Vec<MacroConfig>,
24	}
25	
26	impl Config {
27	    pub fn validate_model_paths(&self) -> Result<()> {
28	        if self.stt.enabled {
29	            let model_path = self
30	                .stt
31	                .model_path
32	                .as_ref()
33	                .context("stt.enabled is true but stt.model_path is not set")?;
34	            ensure_file_exists(model_path, "stt.model_path")?;
35	        }
36	
37	        if self.wake.enabled {
38	            let required = [
39	                (self.wake.encoder.as_ref(), "wake.encoder"),
40	                (self.wake.decoder.as_ref(), "wake.decoder"),
41	                (self.wake.joiner.as_ref(), "wake.joiner"),
42	                (self.wake.tokens.as_ref(), "wake.tokens"),
43	                (self.wake.keywords.as_ref(), "wake.keywords"),
44	            ];
45	
46	            for (path, field) in required {
47	                let path = path.with_context(|| format!("{field} is required when wake.enabled is true"))?;
