38	pub struct Dispatcher {
39	    state: DispatcherState,
40	    matcher: PhraseMatcher,
41	    macros: Arc<RwLock<Vec<MacroConfig>>>,
42	    sound_player: Option<SoundPlayer>,
43	    macro_tx: Sender<MacroCmd>,
44	    default_dwell_ms: u64,
45	    default_gap_ms: u64,
