48	// Dispatcher is safe to send between threads since all its fields are either Send or Arc-wrapped
49	unsafe impl Send for Dispatcher {}
50	unsafe impl Sync for Dispatcher {}
51	
52	impl Dispatcher {
53	    pub fn new(
54	        threshold: f32,
55	        macros: Vec<MacroConfig>,
56	        macro_tx: Sender<MacroCmd>,
57	        default_dwell_ms: u64,
58	        default_gap_ms: u64,
59	    ) -> Self {
60	        let sound_player = match SoundPlayer::new() {
61	            Ok(player) => Some(player),
62	            Err(e) => {
63	                tracing::warn!("Sound player disabled: {}", e);
64	                None
65	            }
66	        };
67	
68	        Self {
69	            state: DispatcherState::new(),
70	            matcher: PhraseMatcher::new(threshold),
71	            macros: Arc::new(RwLock::new(macros)),
72	            sound_player,
73	            macro_tx,
74	            default_dwell_ms,
75	            default_gap_ms,
76	        }
77	    }
78	
79	    pub fn update_macros(&self, new_macros: Vec<MacroConfig>) {
80	        let mut macros = self.macros.write().unwrap();
81	        *macros = new_macros;
82	        tracing::info!("Registry updated with {} macros", macros.len());
83	    }
84	
85	    fn check_condition(&self, if_flag: &Option<String>) -> bool {
86	        match if_flag {
87	            None => true,
88	            Some(if_flag) => {
89	                let required_val = !if_flag.starts_with('!');
90	                let flag_name = if if_flag.starts_with('!') {
91	                    &if_flag[1..]
92	                } else {
93	                    if_flag.as_str()
94	                };
95	                self.state.get(flag_name) == required_val
96	            }
97	        }
98	    }
99	
100	    pub fn process(&self, transcript: &str) -> DispatchOutcome {
101	        let macros = self.macros.read().unwrap();
102	        let candidates = macros
103	            .iter()
104	            .filter(|m| self.check_condition(&m.if_flag))
105	            .filter_map(|m| m.phrase.as_ref().map(|p| (m.name.as_str(), p.as_str())));
106	
107	        if let Some((best_match_name, score)) = self.matcher.find_best_match(transcript, candidates) {
108	            tracing::info!(macro_name = best_match_name, score, "Firing macro");
109	            if let Some(mac) = macros.iter().find(|m| m.name == best_match_name) {
110	                if let Some(sound_path) = &mac.sound {
111	                    if let Some(player) = &self.sound_player {
112	                        if let Err(e) = player.play(sound_path) {
113	                            tracing::error!("Failed to play sound for macro {}: {}", mac.name, e);
114	                        }
115	                    }
116	                }
117	
118	                let keys = mac.keys.iter().map(KeyStep::from_config).collect();
119	                let _ = self.macro_tx.send(MacroCmd::Execute {
120	                    keys,
121	                    default_dwell_ms: self.default_dwell_ms,
122	                    default_gap_ms: self.default_gap_ms,
123	                });
124	
125	                if let Some(set_flag) = &mac.set_flag {
126	                    let new_val = !set_flag.starts_with('!');
127	                    let flag_name = if set_flag.starts_with('!') {
128	                        &set_flag[1..]
129	                    } else {
130	                        set_flag.as_str()
131	                    };
132	                    self.state.set(flag_name, new_val);
133	                }
134	
135	                return DispatchOutcome::Fired {
136	                    macro_id: best_match_name.to_string(),
137	                    score,
138	                };
139	            }
140	        }
141	
142	        tracing::debug!(transcript, "No phrase matched above threshold");
143	        DispatchOutcome::NoMatch
144	    }
145	}
